mapper.select:
SELECT A1.* FROM ( SELECT ROW_NUMBER() OVER ( ORDER BY
destroyRequest.INSERT_DT desc, destroyRequest.DESTROY_REQUEST_NO desc
CAST(${sortColumn} AS INTEGER) ${order}
${sortColumn} ${order}
) AS PAGEINDEX , destroyRequest.DESTROY_REQUEST_NO AS destroyRequestNo , destroyRequest.APPROVAL_LINE_ID AS approvalLineId , destroyRequest.CURRENT_PROCESS_SEQ_NO AS currentProcessSeqNo , destroyRequest.STATUS_CD AS statusCd , FN_GET_CD_NM('destroyRequestStatusCd', destroyRequest.STATUS_CD, #{sessionLang}) AS statusNm , destroyRequest.INSERT_DT AS requestDt , destroyRequest.DESTROY_TYPE AS destroyType , destroyRequest.DESTROY_STATUS_CD AS destroyStatusCd , destroyRequest.BUSINESS_AREA_CD AS businessAreaCd , FN_GET_CD_NM('businessAreaCd', destroyRequest.BUSINESS_AREA_CD, #{sessionLang}) AS businessAreaNm , purchaserUser.USER_CD AS purchaserUserCd /* 구매담당자 */ , purchaserUser.USER_NM AS purchaserUserNm /* 구매담당자 */ , destroyUser.USER_CD AS destroyUserCd /* 폐기자 */ , destroyUser.USER_NM AS destroyUserNm /* 폐기자 */ , info.OBJECT_NO AS objectNo , info.OBJECT_TYPE AS objectType , FN_GET_CD_NM('objectTypeWithP', info.OBJECT_TYPE, #{sessionLang}) AS objectTypeNm , info.DEPLOY_COMPANY_CD AS requestCompanyCd , info.COMPANY_NM AS requestCompanyNm , info.INSERT_USER_CD AS requestUserCd , info.USER_NM AS requestUserNm
FROM ( SELECT destroyRequest.DESTROY_REQUEST_NO DESTROY_REQUEST_NO , request.REQUEST_NO REQUEST_NO , destroyMapping.DESTROY_REQUEST_NO mappingDestroyRequestNo , destroyMapping.OBJECT_NO , destroyMapping.OBJECT_ID , request.OBJECT_TYPE , request.DEPLOY_COMPANY_CD , company.COMPANY_NM , destroyRequest.INSERT_USER_CD , docsUser.USER_NM FROM DOCS_DESTROY_REQUEST destroyRequest INNER JOIN ( SELECT DESTROY_REQUEST_NO , MAX(OBJECT_ID) OBJECT_ID , MAX(OBJECT_NO) OBJECT_NO , MAX(REQUEST_NO) REQUEST_NO , MAX(DEPLOY_USER_CD) DEPLOY_USER_CD FROM DOCS_DESTROY_REQUEST_MAPPING GROUP BY DESTROY_REQUEST_NO ) destroyMapping ON destroyRequest.DESTROY_REQUEST_NO = destroyMapping.DESTROY_REQUEST_NO INNER JOIN DOCS_REQUEST request ON request.REQUEST_NO = destroyMapping.REQUEST_NO INNER JOIN DOCS_COMPANY company ON request.DEPLOY_COMPANY_CD = company.COMPANY_CD INNER JOIN DOCS_USER docsUser ON destroyRequest.INSERT_USER_CD = docsUser.USER_CD
ORDER BY destroyRequest.INSERT_DT desc, destroyRequest.DESTROY_REQUEST_NO desc
ORDER BY ${sortColumn} ${order}, request.REQUEST_NO ${order}
) info INNER JOIN DOCS_DESTROY_REQUEST destroyRequest ON destroyRequest.DESTROY_REQUEST_NO = info.DESTROY_REQUEST_NO INNER JOIN DOCS_DESTROY_REQUEST_DETAIL detail ON destroyRequest.DESTROY_REQUEST_NO = detail.DESTROY_REQUEST_NO AND detail.APPROVAL_STATUS_CD = 'APPROVAL' INNER JOIN DOCS_USER purchaserUser ON purchaserUser.USER_CD = detail.ORIGINAL_USER_CD INNER JOIN DOCS_USER destroyUser ON destroyUser.USER_CD = detail.ACTUAL_USER_CD WHERE 1=1 AND destroyRequest.REQUEST_TYPE = 'DISTRIBUTION'
AND destroyRequest.STATUS_CD = #{statusCd}
AND ORIGINAL_USER_CD = #{purchaserUserCd}
AND destroyRequest.INSERT_DT BETWEEN #{requestStartDt}::DATE AND #{requestEndDt}::DATE
AND destroyRequest.BUSINESS_AREA_CD = #{businessAreaCd}
AND info.OBJECT_TYPE = #{objectType}
AND destroyRequest.COMPANY_CD = #{companyCd}
LIMIT #{end}
) A1
WHERE PAGEINDEX >= #{start}

SELECT COUNT(*) AS TOTAL_COUNT FROM ( SELECT 1 FROM DOCS_DESTROY_REQUEST destroyRequest INNER JOIN ( SELECT DESTROY_REQUEST_NO , MAX(OBJECT_ID) OBJECT_ID , MAX(OBJECT_NO) OBJECT_NO , MAX(REQUEST_NO) REQUEST_NO , MAX(DEPLOY_USER_CD) DEPLOY_USER_CD FROM DOCS_DESTROY_REQUEST_MAPPING GROUP BY DESTROY_REQUEST_NO ) destroyMapping ON destroyRequest.DESTROY_REQUEST_NO = destroyMapping.DESTROY_REQUEST_NO INNER JOIN DOCS_REQUEST request ON request.REQUEST_NO = destroyMapping.REQUEST_NO INNER JOIN DOCS_COMPANY company ON request.DEPLOY_COMPANY_CD = company.COMPANY_CD INNER JOIN DOCS_USER docsUser ON destroyRequest.INSERT_USER_CD = docsUser.USER_CD INNER JOIN DOCS_DESTROY_REQUEST_DETAIL detail ON destroyRequest.DESTROY_REQUEST_NO = detail.DESTROY_REQUEST_NO AND detail.APPROVAL_STATUS_CD = 'APPROVAL' INNER JOIN DOCS_USER purchaserUser ON purchaserUser.USER_CD = detail.ORIGINAL_USER_CD INNER JOIN DOCS_USER destroyUser ON destroyUser.USER_CD = detail.ACTUAL_USER_CD WHERE 1=1 AND destroyRequest.REQUEST_TYPE = 'DISTRIBUTION'
AND destroyRequest.STATUS_CD = #{statusCd}
AND ORIGINAL_USER_CD = #{purchaserUserCd}
AND destroyRequest.INSERT_DT BETWEEN #{requestStartDt}::DATE AND #{requestEndDt}::DATE
AND destroyRequest.BUSINESS_AREA_CD = #{businessAreaCd}
AND info.OBJECT_TYPE = #{objectType}
AND destroyRequest.COMPANY_CD = #{companyCd}
)
